        // ManagerRenderMode. Set explicitly to preserve the .NET 8 appearance.
        _statusStrip.RenderMode = ToolStripRenderMode.System;
        Controls.Add(_statusStrip);
    }
}

public class SafeDropDownEditor : UITypeEditor
{
    public override UITypeEditorEditStyle GetEditStyle(ITypeDescriptorContext? context)
        => UITypeEditorEditStyle.DropDown;

    public override object? EditValue(ITypeDescriptorContext? context,
        IServiceProvider? provider, object? value)
    {
        var editorService = provider?.GetService(typeof(IWindowsFormsEditorService))
            as IWindowsFormsEditorService;
        if (editorService == null) return value;

        var control = CreateDropDownControl(value);
        // .NET 9: DropDownControl(null) now throws ArgumentNullException
        // instead of silently returning. Guard against null.
        if (control != null)
        {
            editorService.DropDownControl(control);
            value = GetValueFromControl(control);
        }
        return value;
    }

    private Control? CreateDropDownControl(object? value) => null;
    private object? GetValueFromControl(Control control) => null;
}

